import { getUserClaims, getUserProfile } from "@/actions/auth";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { checkForHouseholdMembership } from "@/lib/checks/household";
import { redirect } from "next/navigation";

export default async function Dashboard() {
  const userClaims = await getUserClaims();
  if (!userClaims) redirect("/");

  const userProfile = await getUserProfile(userClaims.user.id);
  if (!userProfile) redirect("/");

  await checkForHouseholdMembership(userClaims.user.id);

  const { full_name, email, avatar_url } = userProfile.user;
  return (
    <div>
      <Avatar>
        <AvatarImage src={avatar_url ?? undefined} />
        <AvatarFallback>{email?.charAt(0).toUpperCase() ?? "?"}</AvatarFallback>
      </Avatar>
      <p>Welcome, {full_name ?? email ?? "there"}!</p>
    </div>
  );
}
